const { Pool } = require('pg');

// PostgreSQL connection pool with optimal configuration
const pool = new Pool({
  host: process.env.DB_HOST,
  port: 5432,
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,

  // Connection pool limits
  max: 20, // Maximum pool size (adjust based on DB max_connections)
  min: 5,  // Minimum idle connections to maintain

  // Timeout configurations (milliseconds)
  connectionTimeoutMillis: 5000,  // Max wait time for connection from pool
  idleTimeoutMillis: 30000,       // Close idle connections after 30s
  query_timeout: 10000,            // Query execution timeout: 10s
  statement_timeout: 15000,        // Statement-level timeout: 15s

  // Connection lifecycle
  maxUses: 7500, // Close connections after N queries (prevents memory leaks)

  // Connection validation
  allowExitOnIdle: true // Allow pool to exit when all connections idle
});

// Connection leak detection
pool.on('connect', (client) => {
  client.connectionStartTime = Date.now();
  console.log('Connection acquired from pool');
});

pool.on('remove', (client) => {
  const lifetime = Date.now() - client.connectionStartTime;
  console.log(`Connection removed after ${lifetime}ms`);
});

// Monitor pool health
setInterval(() => {
  console.log({
    total: pool.totalCount,
    idle: pool.idleCount,
    waiting: pool.waitingCount
  });

  // Alert if pool is saturated
  if (pool.waitingCount > 5) {
    console.error('ALERT: Connection pool under heavy load!');
  }
}, 10000); // Check every 10 seconds

// Proper connection usage pattern
async function executeQuery(queryText, params) {
  const client = await pool.connect();
  try {
    const result = await client.query(queryText, params);
    return result.rows;
  } catch (error) {
    console.error('Query error:', error);
    throw error;
  } finally {
    client.release(); // CRITICAL: Always release connection
  }
}

// Graceful shutdown
process.on('SIGTERM', async () => {
  console.log('Draining connection pool...');
  await pool.end();
  process.exit(0);
});

module.exports = { pool, executeQuery };

package com.ansvar.config;

import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import javax.sql.DataSource;

@Configuration
public class DatabaseConfig {

    @Bean
    public DataSource dataSource() {
        HikariConfig config = new HikariConfig();

        // Database connection settings
        config.setJdbcUrl("jdbc:postgresql://localhost:5432/mydb");
        config.setUsername(System.getenv("DB_USER"));
        config.setPassword(System.getenv("DB_PASSWORD"));
        config.setDriverClassName("org.postgresql.Driver");

        // Pool sizing
        config.setMaximumPoolSize(25);  // Maximum connections
        config.setMinimumIdle(5);        // Minimum idle connections

        // Timeout configurations (milliseconds)
        config.setConnectionTimeout(5000);      // Max wait for connection: 5s
        config.setIdleTimeout(300000);          // Close idle connections: 5min
        config.setMaxLifetime(1800000);         // Max connection lifetime: 30min
        config.setValidationTimeout(3000);      // Connection validation: 3s
        config.setLeakDetectionThreshold(60000); // Detect leaks > 60s

        // Connection test query
        config.setConnectionTestQuery("SELECT 1");

        // Pool name for monitoring
        config.setPoolName("AnsvarHikariPool");

        // Performance optimizations
        config.addDataSourceProperty("cachePrepStmts", "true");
        config.addDataSourceProperty("prepStmtCacheSize", "250");
        config.addDataSourceProperty("prepStmtCacheSqlLimit", "2048");

        // PostgreSQL-specific settings
        config.addDataSourceProperty("socketTimeout", "10");  // 10 seconds
        config.addDataSourceProperty("loginTimeout", "5");    // 5 seconds
        config.addDataSourceProperty("connectTimeout", "5");  // 5 seconds

        // Health check
        config.setHealthCheckRegistry(null); // Wire to your metrics registry

        HikariDataSource dataSource = new HikariDataSource(config);

        // Log pool statistics
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Closing HikariCP pool: " + dataSource.getPoolName());
            dataSource.close();
        }));

        return dataSource;
    }
}

// Query timeout annotation for Spring Data JPA
package com.ansvar.repository;

import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.jpa.repository.QueryHints;
import javax.persistence.QueryHint;
import java.util.List;

public interface UserRepository extends JpaRepository<User, Long> {

    @QueryHints({
        @QueryHint(name = "javax.persistence.query.timeout", value = "5000"), // 5 seconds
        @QueryHint(name = "org.hibernate.timeout", value = "5")
    })
    @Query("SELECT u FROM User u WHERE u.email = :email")
    User findByEmailWithTimeout(String email);
}

// Circuit breaker pattern for database calls
package com.ansvar.service;

import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.Service;

@Service
public class UserService {

    private final UserRepository userRepository;

    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @CircuitBreaker(name = "databaseService", fallbackMethod = "getUserFallback")
    public User getUser(String email) {
        return userRepository.findByEmailWithTimeout(email);
    }

    private User getUserFallback(String email, Exception ex) {
        // Return cached data or default response
        throw new ServiceUnavailableException("Database temporarily unavailable");
    }
}

const { Pool } = require('pg');
const monitor = require('pg-monitor');
const prometheus = require('prom-client');

// Initialize Prometheus metrics
const poolTotalGauge = new prometheus.Gauge({
  name: 'db_pool_connections_total',
  help: 'Total number of connections in pool'
});

const poolIdleGauge = new prometheus.Gauge({
  name: 'db_pool_connections_idle',
  help: 'Number of idle connections in pool'
});

const poolWaitingGauge = new prometheus.Gauge({
  name: 'db_pool_connections_waiting',
  help: 'Number of clients waiting for connection'
});

const queryDurationHistogram = new prometheus.Histogram({
  name: 'db_query_duration_seconds',
  help: 'Query execution duration in seconds',
  buckets: [0.1, 0.5, 1, 2, 5, 10]
});

const connectionLeaksCounter = new prometheus.Counter({
  name: 'db_connection_leaks_total',
  help: 'Total number of detected connection leaks'
});

// PostgreSQL connection pool
const pool = new Pool({
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 5000
});

// Enable pg-monitor for detailed connection tracking
if (process.env.NODE_ENV !== 'production') {
  monitor.attach(pool, {
    query: true,
    connect: true,
    disconnect: true,
    error: true
  });
}

// Track active connections with metadata
const activeConnections = new Map();

pool.on('connect', (client) => {
  const connectionId = Math.random().toString(36).substr(2, 9);
  client._connectionId = connectionId;
  client._acquiredAt = Date.now();
  client._acquiredStack = new Error().stack;

  activeConnections.set(connectionId, {
    acquiredAt: client._acquiredAt,
    stack: client._acquiredStack
  });

  console.log(`[${connectionId}] Connection acquired`);
});

pool.on('remove', (client) => {
  const connectionId = client._connectionId;
  const lifetime = Date.now() - client._acquiredAt;

  activeConnections.delete(connectionId);
  console.log(`[${connectionId}] Connection released after ${lifetime}ms`);
});

// Connection leak detection (runs every 30 seconds)
setInterval(() => {
  const now = Date.now();
  const leakThreshold = 60000; // 60 seconds

  for (const [connectionId, metadata] of activeConnections.entries()) {
    const age = now - metadata.acquiredAt;

    if (age > leakThreshold) {
      console.error(`⚠️  LEAK DETECTED: Connection ${connectionId} held for ${age}ms`);
      console.error('Stack trace when acquired:', metadata.stack);
      connectionLeaksCounter.inc();

      // Send alert (integrate with PagerDuty, Slack, etc.)
      sendAlert({
        severity: 'critical',
        title: 'Database Connection Leak Detected',
        description: `Connection held for ${age}ms`,
        connectionId,
        stack: metadata.stack
      });
    }
  }
}, 30000);

// Pool health monitoring (every 10 seconds)
setInterval(() => {
  const metrics = {
    total: pool.totalCount,
    idle: pool.idleCount,
    waiting: pool.waitingCount
  };

  // Update Prometheus metrics
  poolTotalGauge.set(metrics.total);
  poolIdleGauge.set(metrics.idle);
  poolWaitingGauge.set(metrics.waiting);

  // Alert on pool saturation
  const utilization = (metrics.total - metrics.idle) / pool.options.max;
  if (utilization > 0.8) {
    console.warn(`⚠️  Pool utilization high: ${(utilization * 100).toFixed(1)}%`);
  }

  if (metrics.waiting > 3) {
    console.error(`🚨 Connection pool exhaustion risk: ${metrics.waiting} waiting`);
    sendAlert({
      severity: 'warning',
      title: 'Connection Pool Near Exhaustion',
      description: `${metrics.waiting} clients waiting for connections`
    });
  }
}, 10000);

// Wrapper for query execution with monitoring
async function executeQuery(queryText, params) {
  const startTime = Date.now();
  const client = await pool.connect();

  try {
    const result = await client.query(queryText, params);
    const duration = (Date.now() - startTime) / 1000;

    queryDurationHistogram.observe(duration);

    if (duration > 5) {
      console.warn(`Slow query detected (${duration}s):`, queryText);
    }

    return result.rows;
  } catch (error) {
    console.error('Query error:', error);
    throw error;
  } finally {
    client.release();
  }
}

// Alert function (integrate with your alerting system)
function sendAlert(alert) {
  // Example: Send to Slack, PagerDuty, etc.
  console.error('ALERT:', JSON.stringify(alert, null, 2));
  // TODO: Integrate with actual alerting service
}

module.exports = { pool, executeQuery };
